	select
            t1.DATA_1,
            t1.LAST_UPDATE_IP,
            t1.CREATED_DEPT,
            t1.CREATION_DATE,
            t1.DATA_2,
            t1.CREATED_BY,
            t1.VERSION,
            t1.ID,
            t1.LAST_UPDATE_DATE,
            t1.LAST_UPDATED_BY,
            t1.ORG_IDENTITY,
        v.ACTIVITYALIAS_, v.BUSINESSSTATE_,v.DBID_ as PROCESSINSTANCEID
	from DYN_TEST 	t1 left join BPM_CLIENT_HIST_PROCINST_V v on t1.id = v.formid_
		
			
						   		   			
		                		                  and t1.DATA_1  like concat(concat('%',#{bean.DATA_1}),'%')
		                		            
		            			    			   		   			
		                		                  and t1.LAST_UPDATE_IP  like concat(concat('%',#{bean.LAST_UPDATE_IP}),'%')
		                		            
		            			    			   		   			
		                		                  and t1.CREATED_DEPT  like concat(concat('%',#{bean.CREATED_DEPT}),'%')
		                		            
		            			    			   	                
						and t1.CREATION_DATE >= #{bean.CREATION_DATE_START}
					
					
						and t1.CREATION_DATE <= #{bean.CREATION_DATE_END}
					
                   
                       and t1.CREATION_DATE = #{bean.CREATION_DATE}
                   
			   			    			   		   			
		                		                  and t1.DATA_2  like concat(concat('%',#{bean.DATA_2}),'%')
		                		            
		            			    			   		   			
		                		                  and t1.CREATED_BY  like concat(concat('%',#{bean.CREATED_BY}),'%')
		                		            
		            			    			   	                
						and t1.VERSION >= #{bean.VERSION_START}
					
					
						and t1.VERSION <= #{bean.VERSION_END}
					
                   
                       and t1.VERSION = #{bean.VERSION}
                   
			   			    			   		   			
		                			              and t1.ID =#{bean.ID}
			            		            
		            			    			   	                
						and t1.LAST_UPDATE_DATE >= #{bean.LAST_UPDATE_DATE_START}
					
					
						and t1.LAST_UPDATE_DATE <= #{bean.LAST_UPDATE_DATE_END}
					
                   
                       and t1.LAST_UPDATE_DATE = #{bean.LAST_UPDATE_DATE}
                   
			   			    			   		   			
		                		                  and t1.LAST_UPDATED_BY  like concat(concat('%',#{bean.LAST_UPDATED_BY}),'%')
		                		            
		            			    			   		   			
		                		                  and t1.ORG_IDENTITY  like concat(concat('%',#{bean.ORG_IDENTITY}),'%')
		                		            
		            			    			

                and exists (select 1 from BPM_CLIENT_HIST_TASK_V os where os.task_b_id_ = t1.id and os.assignee_ = #{bean.currUserId})

            
                and v.businessstate_ = #{bean.bpmState}
            

			
				and ${sql}
			
		
		
	        
	            order by ${P_OrderBy}
	        
	        
	            order by t1.creation_date desc

